<template>
  <div>
    <b-row class="mt-1 mt-lg-3">
      <b-col lg="8" offset-lg="2">
        <h1>Create your account</h1>
        <b-form @submit.stop.prevent="onSubmit">
          <b-form-group label="Email:">
            <b-form-input
              type="email"
              v-model="$v.form.email.$model"
              :state="validateState('email')"
              placeholder="Enter Email"
            ></b-form-input>
            <b-form-invalid-feedback v-if="!$v.form.email.required">
              This field is required.
            </b-form-invalid-feedback>
            <b-form-invalid-feedback v-if="!$v.form.email.email">
              Invalid Email.
            </b-form-invalid-feedback>
          </b-form-group>

          <b-form-group label="Birth Date:">
            <b-input-group :prepend="age" class="mt-3">
              <b-form-input
                type="date"
                v-model="$v.form.birthDate.$model"
                :state="validateState('birthDate')"
              ></b-form-input>
              <b-form-invalid-feedback v-if="!$v.form.birthDate.required">
                This field is required.
              </b-form-invalid-feedback>
              <b-form-invalid-feedback v-if="!$v.form.birthDate.validAge">
                Invalid age, your age must be greater than equal 18.
              </b-form-invalid-feedback>
            </b-input-group>
          </b-form-group>

          <b-form-group label="Gender:">
            <b-form-radio-group v-model="form.gender">
              <b-form-radio :value="true">Male</b-form-radio>
              <b-form-radio :value="false">Female</b-form-radio>
            </b-form-radio-group>
          </b-form-group>

          <hr />

          <b-form-group label="Username:">
            <b-form-input
              type="text"
              placeholder="Enter Username"
              v-model.trim="$v.form.username.$model"
              :state="validateState('username')"
            ></b-form-input>
            <b-form-invalid-feedback v-if="!$v.form.username.required">
              This field is required.
            </b-form-invalid-feedback>
            <b-form-invalid-feedback v-if="!$v.form.username.minLength">
              Username must be greater than equal 6 characters.
            </b-form-invalid-feedback>
            <b-form-invalid-feedback v-if="!$v.form.username.maxLength">
              Username must be less than equal 32 characters.
            </b-form-invalid-feedback>
          </b-form-group>

          <b-form-group label="Password:">
            <b-form-input
              type="password"
              placeholder="Enter Password"
              v-model="$v.form.password.$model"
              :state="validateState('password')"
            ></b-form-input>
            <b-form-invalid-feedback v-if="!$v.form.password.required">
              This field is required.
            </b-form-invalid-feedback>
            <b-form-invalid-feedback v-if="!$v.form.password.minLength">
              Password must be greater than equal 6 characters.
            </b-form-invalid-feedback>
            <b-form-invalid-feedback v-if="!$v.form.password.maxLength">
              Password must be less than equal 32 characters.
            </b-form-invalid-feedback>
          </b-form-group>

          <b-form-group label="Confirm Password:">
            <b-form-input
              type="password"
              placeholder="Re-enter Password"
              v-model="$v.form.confirmPassword.$model"
              :state="
                validateState('confirmPassword') && validateState('password')
              "
            ></b-form-input>
            <b-form-invalid-feedback v-if="!$v.form.password.sameAs">
              Confirm password not match.
            </b-form-invalid-feedback>
          </b-form-group>

          <b-form-group>
            <b-form-checkbox
              :value="true"
              :unchecked-value="false"
              v-model="$v.form.isAccepted.$model"
              :state="validateState('isAccepted')"
            >
              I accept the
              <router-link to="/terms" target="_blank">terms</router-link> and
              use.
            </b-form-checkbox>
          </b-form-group>

          <b-form-group>
            <b-button variant="success" type="submit" class="mr-1"
              >Sign up</b-button
            >
            <b-button
              variant="outline-primary"
              @click="$router.go(-1)"
              class="ml-1"
              >Back</b-button
            >
          </b-form-group>
        </b-form>
      </b-col>
    </b-row>
  </div>
</template>

<script>
import {
  required,
  minLength,
  maxLength,
  minValue,
  sameAs,
  email
} from "vuelidate/lib/validators";

export default {
  computed: {
    age() {
      const age = this.getAge(this.$v.form.birthDate.$model);
      if (isNaN(age)) {
        return "Invalid Birth Date";
      }
      return `Age: ${age}`;
    }
  },
  data() {
    return {
      form: {
        email: "",
        gender: true,
        birthDate: new Date(
          new Date().setFullYear(new Date().getFullYear() - 18)
        )
          .toISOString()
          .slice(0, 10),
        username: "",
        password: "",
        confirmPassword: "",
        isAccepted: false
      }
    };
  },
  validations: {
    form: {
      email: {
        required,
        email
      },
      birthDate: {
        required,
        validAge: function(value) {
          const age = this.getAge(value);
          return  age >= 18;
        }
      },
      username: {
        required,
        minLength: minLength(6),
        maxLength: maxLength(32)
      },
      password: {
        required,
        minLength: minLength(6),
        maxLength: maxLength(32)
      },
      confirmPassword: {
        sameAs: sameAs("password")
      },
      isAccepted: {
        required: value => value
      }
    }
  },
  methods: {
    validateState(name) {
      const { $dirty, $error } = this.$v.form[name];
      return $dirty ? !$error : null;
    },
    onSubmit() {
      this.$v.form.$touch();
      if (this.$v.form.$anyError) {
        return;
      }
      alert("success");
      this.$router.push("/sign-in");
    },
    getAge(dateString) {
      if (!dateString || dateString.length === 0) {
        return NaN;
      }
      let today = new Date();
      let birthDate = new Date(dateString);
      let age = today.getFullYear() - birthDate.getFullYear();
      let m = today.getMonth() - birthDate.getMonth();
      if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
        age--;
      }
      return age;
    }
  }
};
</script>

